var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>챔버</color>","JPN":"管理局直轄都市<color=#ffd34c>チェンバー</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Chamber</color>","TWN":"管理局直轄市<color=#ffd34c>強巴</color>"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"subtitle","speaker":null,"text":{"KOREA":"시라사키 리프트 코퍼레이션\\n대균열 왕복 승강장 <color=#ffd34c>4-D</color>","JPN":"シラサキ・リフト・コーポレーション\\n大亀裂往復乗降場<color=#ffd34c>4-D</color>","ENG":"Sirasaki Lifting Company\\nGrand Dimension Crevice Elevator <color=#ffd34c>4-D</color>","TWN":"白崎起重所屬\\n大峽谷往返升降機 <color=#ffd34c>4-D</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"승강기 배치 및 점검 완료되었습니다!","JPN":"昇降機の配置および点検、完了しました！","ENG":"The elevator's been inspected and placed!","TWN":"升降機部署及檢查完畢！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"다들 아시죠? 권장 체류 시간은 24시간이고요. 하강하겠습니다!","JPN":"皆さんご存じですよね？　滞在推奨時間は24時間です。では降ります！","ENG":"You all know, right? The recommended stay time is 24 hours. Descend!","TWN":"不用再說一遍了吧？建議停留時間是24小時。現在開始下降！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"승강기 하강!","JPN":"昇降機、下降！","ENG":"Elevator going down!","TWN":"升降機啟動！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"오오, 신기하네요.","JPN":"おお、不思議な感じですね。","ENG":"Whoa, this is incredible.","TWN":"喔喔，真神奇啊。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L18_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"차원함선을 쓰지 않고, 승강기를 이용한 다이브라니.","JPN":"次元艦船じゃなく昇降機を利用したダイブだなんて。","ENG":"A dive using an elevator instead of a dimensional ship.","TWN":"不使用次元戰艦，而是使用升降機進行躍入。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"하핫, 그라운드 원에서 왔다더니 초짜인가 보구만.","JPN":"ははっ、グラウンド・ワンから来たと聞いたが、初心者なんだな。","ENG":"Haha! I heard you were from Ground One, but guess you are a rookie, eh?","TWN":"哈哈，從G1來的吧？看來是個新手啊。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"여기 챔버 대균열은 다른 도시와 달리, 지하 깊은 곳에 위치하기 때문이야.","JPN":"ここチェンバーの大亀裂は他の都市とは違って、地下の深い場所にあるからだ。","ENG":"Chamber's Grand Dimension Crevice is unlike those of the other cities. It's located deep underground.","TWN":"強巴的大峽谷與其他城市不同，開在了地下深處。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"이런 곳에는 거대한 차원 함선이 진입하기 쉽지 않거든.","JPN":"こういった場所では巨大な次元艦船だと出入りしづらいんでな。","ENG":"Also, it's hard for something as massive as a dimensional ship to enter a place like this.","TWN":"這種地方，巨大的次元艦船可不容易進來。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"프론트베이의 해저 대균열과 비슷하네요.","JPN":"フロントベイの海底大亀裂と似ていますね。","ENG":"It's similar to the one in Front Bay.","TWN":"和前灣的海底大峽谷很相似呢。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"그쪽도 특수한 차원 함선을 써야, 대균열로 다이브가 가능하다고 들었거든요.","JPN":"そこも特殊な次元艦船じゃないと大亀裂にダイブできないと聞きました。","ENG":"I heard that they also have to use a special dimensional ship to dive into the Grand Dimension Crevice.","TWN":"聽說他們也需要使用特殊的次元戰艦，才能潛入大峽谷。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"오, 듣고 보니 그렇구만.","JPN":"おお、そういえばそうだったな。","ENG":"Oh, come to think of it, you're right.","TWN":"喔，聽你這麼一說，確實是這樣。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"어쨌든 지하 대균열로 인해, 챔버의 이면세계 탐사는 독특한 방식으로 발전해왔어.","JPN":"とにかく地下の大亀裂の影響で、チェンバーの裏世界探査は独自の方法を発展させてきた。","ENG":"Anyway, due to the underground Grand Dimension Crevice, the Counterside expedition in Chamber has developed in a unique way.","TWN":"無論如何，由於地下大峽谷的存在，強巴的異界探索就以這種獨特的方式發展起來了。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 그 규모도 부대 단위의 태스크포스보다는 소규모 탐사대 위주지.","JPN":"だから、規模も部隊ごとのタスクフォースよりは、小規模の探査部隊が中心だ。","ENG":"That's why we tend to form exploration teams smaller than that of TASKFORCEs.","TWN":"所以規模上也更傾向於小型探險隊，而不是部隊級別的特遣隊。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"탐사가 많이 진행된 층 위주로 다니면 자네도 안전할 거야.","JPN":"探査が進んでいる階層を中心に移動すれば、君も安全だろうさ。","ENG":"You'll be safe as long as you stay on the floors that have already been explored a lot.","TWN":"如果你主要在已經探查過的層面活動，會比較安全。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 3층보다 아래로 내려가면 이야기가 달라지겠지만.","JPN":"もちろん、3階より下は話が違ってくるけどな。","ENG":"Of course, it's an entirely different case if you go below the 3rd floor.","TWN":"當然，如果你下到第三層以後，那情況就不一樣了。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"어어, 3층보다 아래로 내려가면 어떻게 되는데요?","JPN":"え、3階より下に行くと、どうなるんですか？","ENG":"Uh, what happens if I go below the 3rd floor?","TWN":"呃呃，到3層之後會怎麼樣？"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 표정을 보니 잔뜩 겁먹은 모양이군.","JPN":"ふふ、その顔は……怖気づいたな？","ENG":"Haha, don't get too scared already.","TWN":"呵呵，看你的表情，嚇壞了吧。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"딱 한 번.","JPN":"一度だけ。","ENG":"Just once.","TWN":"有一次。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"승강기가 고장 나서 3층에 내려버린 적이 있었지.","JPN":"昇降機が故障して、3階に降りてしまったことがある。","ENG":"I got off on the 3rd floor because the elevator broke down.","TWN":"電梯壞了，我們被困在了三層。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"이 승강기로 내려갈 수 있는 최저 지점이 3층이었거든.","JPN":"この昇降機で降りられる最低地点が3階だったんだ。","ENG":"You see, the lowest point this elevator can go is the 3rd floor.","TWN":"順便說一下，這部升降梯能到達的最深層就是三層。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"탐사대에 엔지니어가 있어서 승강기를 고쳐보려 했지만, 역부족이었어.","JPN":"探査部隊のエンジニアが何とか直せないかと手を尽くしてはみたが、無理だった。","ENG":"Our team had an engineer and we tried to fix the elevator, but we failed to do it.","TWN":"儘管探險隊裡有工程師試圖搶修，但還是不夠。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"어쩔 수 없이 우리는 지상으로 향하는 다른 승강기까지 어둠 속을 헤쳐 가야 했지.","JPN":"しかたなく俺たちは地上へ向かう他の昇降機まで、暗闇を進むしかなかった。","ENG":"We had no choice but to walk through the darkness to reach the other elevator that was going up.","TWN":"無奈之下，我們只能在黑暗中穿行，前往另一個通向地面的電梯。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"그, 그래서요?","JPN":"そ、それで？","ENG":"A-and?","TWN":"那，然後呢？"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"다 죽었어. 길잡이였던 나를 빼고 말이야.","JPN":"皆死んだよ。案内役だった俺を除いて。","ENG":"They all died. Except me, who was the guide.","TWN":"全都死了。除了我這個帶路的之外。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"네……?","JPN":"え……？","ENG":"What...?","TWN":"這……？"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"하, 하하. 겁주려고 하는 말씀이죠?","JPN":"は、はは……冗談ですよね？　怖がらせないでくださいよ。","ENG":"Ha, haha. You're just trying to scare me, right?","TWN":"哈，哈哈。你這是在嚇唬我吧？"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"정말이야. 3종이 나타나 버렸거든.","JPN":"本当の話さ。第3種が現れたんだ。","ENG":"It's true. A Category 3 appeared.","TWN":"真的，我們遇到了3類……"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"자네도 이 승강기에 탈 때 서명하지 않았나?","JPN":"君もこれに乗る時サインしたんじゃないか？","ENG":"Didn't you sign the waiver before boarding the elevator?","TWN":"你上這升降機的時候不是也簽了字嗎？"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"회사는 탐사대의 신변에 대해 아무것도 책임지지 않는다고 말이야.","JPN":"会社は探査部隊の身辺に対して一切責任を取らないという同意書に。","ENG":"That the company isn't liable for anything that happens to the exploration team?","TWN":"公司可不對探險隊的安危負責。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"아하하! 그래도 걱정할 것 없네!","JPN":"ははは！　でも心配する必要はない！","ENG":"Ah hah hah! But there's nothing to worry about!","TWN":"啊哈哈！不過不用擔心！"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"지금 가는 2층 샹그릴라 동토는 내 집 드나들 듯이 가 본 곳이니까.","JPN":"今向かっている2階のシャングリラ凍土は、自分の家のように出入りしてる場所だからな。","ENG":"The 2nd floor known as the Gelid Lands of Shangri-La is a place that I know like the back of my hand.","TWN":"現在要去的只是二層香格里拉凍土，我在那裡就像回家一樣熟悉。"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"오, 완전 믿음직스러운데요?","JPN":"おお、頼もしいですね！","ENG":"Oh, that's reassuring.","TWN":"啊哈哈……真是讓人放心呢？"},"stage":{"bg":"GAME_LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"강하 완료.","JPN":"降下完了。","ENG":"Descend complete.","TWN":"下降完成。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"자, 젊은이. 이제 돈 벌러……","JPN":"さ、若もん。稼ぎに……","ENG":"Now, let's go make some money, young–","TWN":"好，年輕人。現在去賺錢吧……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":" 크흑!!","JPN":" くうっ！！","ENG":" Kuh!!","TWN":"咳咳！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"너, 너 이게 지금 무슨 짓이야……!?","JPN":"き、君……何をするんだ……！？","ENG":"What... did you do that for...?!","TWN":"你，你這是幹什麼……！?"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"안심하세요, 얕게 베었으니까.","JPN":"ご安心ください。傷は浅いですから。","ENG":"Don't worry. It was a shallow cut.","TWN":"放心吧，只是輕輕劃了一下。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"웃기지 마! 여기선 조그만 상처라도 치명적이라고!!","JPN":"ふざけるな！　ここでは小さな傷も致命傷になりかねないんだ！","ENG":"Are you kidding me?! Even a small cut is fatal down here!!","TWN":"別逗了！在這裡哪怕是小傷也會致命的！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"침식파에 상처가 노출되기라도 한다면……!","JPN":"侵食波に傷が露出されたりでもしたら……！","ENG":"If the wound is exposed to the Corruption ray...!","TWN":"如果傷口暴露在侵蝕波下……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"네, 정답이에요.","JPN":"ええ、まさにその通り。","ENG":"Yes, you are right.","TWN":"是的，答對了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 목숨이 아깝다면 순순히 제 말을 들으시는 편이 좋을 거예요.","JPN":"だから命が惜しければ、大人しく私の言うことを聞いた方がいいですよ。","ENG":"So, if you wish to live, it would be best to listen to me.","TWN":"所以，如果你珍惜自己的命，最好乖乖聽我的話。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 카운터가 아니니까.","JPN":"あなたはカウンターではないから。","ENG":"Because you're not a Counter.","TWN":"你不是制裁者吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"스, 스완……?","JPN":"す、スワン……？","ENG":"S-Swan...?","TWN":"史，史旺……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"샤레이드의 스완 맞지!? 스완이 왜 여기에……!?","JPN":"シャレードのスワンだよな！？　スワンがなぜここに……！？","ENG":"You're Swan from Charade, right?! What are you doing here...?!","TWN":"你是那個……查雷德的史旺，對吧！？為什麼會在這裡……！?"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 왜 여기에 있는지는 당신과 관계없겠죠.","JPN":"私がなぜここにいるのか、それはあなたとは関係のないことです。","ENG":"Why I'm here is none of your concern.","TWN":"我為什麼在這裡，跟你沒關係吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 할 일은 하나예요. 저를 여기보다 심층으로 안내하는 것.","JPN":"あなたのやるべきことは一つ。私をここより深い、深層部へ案内すること。","ENG":"The only thing you should be concerned about is taking me deeper.","TWN":"你只有一個任務。帶我進入深層。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"심층이라면 강하 한계선, <color=#ffd34c>5층</color>을 말하는 거야……?","JPN":"深層部なら、降下限界線……<color=#ffd34c>5階</color>のことか……？","ENG":"Deeper? Are you talking about the limit point of descent? The <color=#ffd34c>5th floor</color>...?","TWN":"深層的話，是指極限下降位置，<color=#ffd34c>地下5層</color>……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"무리야! 5층에서 살아 돌아온 귀환자는 한 명도 없다고!","JPN":"無理だ！　5階に行って戻ってきた人は一人もいない！","ENG":"I can't do that! No one has returned from the 5th floor alive!","TWN":"不、不行！不可能的！從地下5層活著回來的人一個都沒有！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"알고 있어요.","JPN":"知っています。","ENG":"I know that.","TWN":"我知道。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"사전 조사에 따르면 5층으로 향하는 승강기는 벌써 몇 년 전에 고장 났다고 하더군요.","JPN":"調べたところ、5階に向かう昇降機は数年まえに故障したらしいですね。","ENG":"According to my research, the lift to the 5th floor's been out of commission for years.","TWN":"根據事先的調查，通往5層的升降機幾年前就已經壞了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초에 고장이 아니었다고 해도, 그 승강기를 쓰지는 않았을 거예요.","JPN":"そもそも、故障していなくてもそれに乗ることはなかったでしょう。","ENG":"But even if it wasn't broken, I wouldn't have used it anyway.","TWN":"但即使一開始沒有壞，我也不會用那部升降機的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그걸 쓰면, 필요 이상으로 다른 사람들의 이목을 끌게 될 테니까.","JPN":"それを使えば、必要以上に目立ってしまいますから。","ENG":"Because going down in that will attract more attention than necessary.","TWN":"用那個的話，會引起不必要的關注。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그래서 일부러……?","JPN":"そ、それでわざと……？","ENG":"Th-that's why you deliberately...?","TWN":"是、所以故意這樣……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 그래서 일부러 가장 만만한 이 승강기를 고른거죠.","JPN":"そうです。それでわざと、一番無難なこの昇降機を選んだのです。","ENG":"Yes. I chose the lift that was most easily accessible.","TWN":"是啊。所以才故意選了這個最普通的升降機。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 가장 만만한 당신을 고른 거고요.","JPN":"そして、一番容易に言うことを聞きそうなあなたを選んだ。","ENG":"And also you, the easiest person I could find.","TWN":"然後選了你這個最普通的目標。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이 승강기는 3층까지 밖에…… ","JPN":"でも、この昇降機は3階までしか…… ","ENG":"But this elevator only goes to the 3rd floor–","TWN":"但這個升降機只能到三層……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"힉!?","JPN":"ひいっ！？","ENG":"Whoa?!","TWN":"噫？!"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"절 시험하려고 하지 마세요.","JPN":"私を試すようなことは言わないでください。","ENG":"Don't test me.","TWN":"別試圖考驗我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 말했잖아요? 3층에서 승강기가 고장 나, 다른 승강기를 통해서 지상으로 나왔다고.","JPN":"あなたが言ったではないですか。3階で昇降機が故障し、他の昇降機に乗って地上に戻ったと。","ENG":"You said it yourself that the lift broke down on the 3rd floor and you had to go back up using another one.","TWN":"你不是說了嗎？三層的升降機壞了，透過另一部升降機回到了地面。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 말은 각 층마다 다른 층으로 연결되는 승강기가 존재한다는 겁니다.","JPN":"それはつまり、各階には別の階に繋がる昇降機が存在するという意味ですね。","ENG":"That implies that each floor has a lift connected to each other.","TWN":"這表示每層之間都架有通往其他層的升降機。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그렇다고 해도 5층까지 가는 건 불가능해!","JPN":"だ、だからといって5階に行くのは不可能だ！","ENG":"E-even if that's the case, it's impossible to go down to the 5th floor!","TWN":"即使如此，去五層也是不可能的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"그건, 자살행위라고……!","JPN":"あれは自殺行為同然だぞ……！","ENG":"That's suicide...!","TWN":"那是，自殺行為啊……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"반드시 5층일 필요는 없어요.","JPN":"必ずしも5階である必要はありません。","ENG":"It doesn't have to the 5th floor.","TWN":"不一定非得是5層。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대균열과 현실이 서로 강하게 간섭하는 지점을 찾으면 되니까요.","JPN":"大亀裂と現実が強く干渉し合うポイントさえ見つけられればいいんです。","ENG":"I just need to find the point where the Grand Dimension Crevice and the Normalside interfere with each other the strongest.","TWN":"只要找到大峽谷與現實強烈干涉的地方就行。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 저를 4층으로 안내해 주세요.","JPN":"だから私を4階へ案内してください。","ENG":"So, please lead the way to the 4th floor.","TWN":"所以請帶我去4層吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"4층…….","JPN":"4階……","ENG":"The 4th floor...","TWN":"地下四層……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"……좋아.","JPN":"……いいだろう。","ENG":"...All right.","TWN":"……好，好吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"대신, 내 안전을 보장해 줘. 그 정도는 해줄 수 있잖아?","JPN":"その代わり、俺の安全を保証してくれ。それぐらいは頼めるよな？","ENG":"Instead, ensure my safety. You can do that much, right?","TWN":"作為交換，要保證我的安全。這點你能做到吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요.","JPN":"わかりました。","ENG":"Very well.","TWN":"很好。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"안내가 끝날 때까지는 당신의 안전을 보장하죠.","JPN":"案内が終わるまでは、あなたの安全を保証します。","ENG":"Until your services end, I will guarantee your safety.","TWN":"在指引結束之前，我會保證你的安全。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"제길, 이터니움 실드의 잔량 손실이 눈에 보일 정도야.","JPN":"くそ、エタニウムシールドの残量損失が肉眼で確認できるぐらいだ。","ENG":"Dammit! I can see the Eternium shield running out significantly.","TWN":"該死，永恆之金護盾剩餘量肉眼可見地減少了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"이봐, 스완! 4층에 도착한지도 한참이 지났어!","JPN":"おい、スワン！　もう4階についてからずいぶん経つぞ！","ENG":"Hey, Swan! It's been hours since we've been on the 4th floor!","TWN":"喂，史旺！到4層已經有一段時間了！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"대체 뭘 찾는 거야!","JPN":"いったい何を探しているんだ！","ENG":"What are you even looking for?!","TWN":"到底還要找什麼！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"……그만.","JPN":"……静かに。","ENG":"...Stop.","TWN":"……可以了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"이쯤이라면 썩 나쁘지 않군요.","JPN":"この辺りなら、悪くないですね。","ENG":"I think this isn't such a bad point.","TWN":"這個程度的話，還不算太糟糕。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로…… 네 번째.","JPN":"これで……四つ目。","ENG":"This will make it... the fourth one.","TWN":"這便是……第四個。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"챔버 대균열은 민간 출입이 자유로워서 비교적 수월했네요.","JPN":"チェンバー大亀裂は民間人の出入りが自由だから、比較的スムーズに来れましたね。","ENG":"It was relatively easy to complete because Chamber's Grand Dimension Crevice is accessible to ordinary people.","TWN":"多虧允許平民出入，接近大峽谷才相對容易。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"허공에 유리 조각들이 갑자기 사라졌어……?","JPN":"ガラスの欠片が……宙に浮かんで消えた……？","ENG":"A piece of glass suddenly disappeared into thin air...?","TWN":"空氣中的玻璃碎片消失了……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"대체 뭘 하는 거지?","JPN":"いったい何をしているんだ？","ENG":"What did you do?","TWN":"你到底在做什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"의식을 치르고 있는 중이랍니다. 다른 세계의 무언가를 불러내는 의식을.","JPN":"儀式を行っているのです。別の世界の何かを呼び出す儀式を。","ENG":"I'm performing a ritual. One that will summon something from another world.","TWN":"正在進行儀式。召喚其他世界的某種存在的儀式。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"다른 세계의 무언가?","JPN":"別の世界の何か？","ENG":"Something from another world?","TWN":"另一個世界的存在？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 침식파 탐지기가……?","JPN":"待て、侵食波探知機が……？","ENG":"Wait, the Corruption ray detector...","TWN":"等一下，侵蝕波探測器……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"CSE 레벨 3 이상에서만 울리도록 해놨는데……?","JPN":"CSEレベル3以上じゃないと鳴らないようにしておいたのに……？","ENG":"But I set it to go off only when the CSE Level is above 3...?","TWN":"我設定了只有在CSE等級3以上才會響啊……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"이, 이쪽으로 온다……!!","JPN":"こ、こっちに来る……！！","ENG":"I-It’s coming this way...!!","TWN":"來，來這邊了……！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물러서세요.","JPN":"下がりなさい。","ENG":"Get back.","TWN":"請退後。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"고등급 침식체를 단 일격에……?","JPN":"高レベルの侵食体を一撃で……？","ENG":"A high-category C.O. went down in a single strike...?","TWN":"高類侵蝕體……被秒殺了？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"너, 대체 정체가 뭐야……?","JPN":"き、君……いったい何者なんだ……？","ENG":"What... are you...?","TWN":"你，到底是什麼人……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"정말로 내가 아는 그 스완이 맞아?","JPN":"本当に俺の知っているあのスワンなのか？","ENG":"Are you really the Swan that I know?","TWN":"真的是那個演員史旺嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 모두가 타인을 대할 때 적당한 가면을 고르지 않나요?","JPN":"さあ、誰しも他人に接する時は、相応の仮面を被るものでしょう。","ENG":"Well, doesn't everyone choose an appropriate mask when dealing with other people?","TWN":"這個麼？人在面對他人時不都會選擇戴上合適的面具嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비슷한 거예요. 상대방이 원하는 배역을 연기해주면, 바라는 걸 쉽게 얻을 수 있으니까.","JPN":"それと同じです。相手の望む役を演じてあげれば、こちらも目的を果たすのは容易い。","ENG":"Let's say it's something similar. Because it's easier to get what I want if I play the role others expect.","TWN":"差不多的道理。只要演好對方期望的角色，就能輕鬆得到自己想要的東西。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"신비주의 배우, 천재 각본가, 국제적 테러리스트, 관리국 비밀요원 그리고…… 악의 하인.","JPN":"謎の多い女優、天才脚本家、国際的テロリスト、管理局のエージェント、そして……悪のしもべ。","ENG":"The mysterious actress, genius scriptwriter, international terrorist, the Administration's secret agent, and... a servant of evil.","TWN":"神秘的女演員、天才編劇、國際恐怖分子、管理局秘密特工，還有……惡的僕人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저에게 어떤 가면을 기대하고 계셨던 건지는 모르겠지만.","JPN":"私に期待していたものがどの仮面かはわかりませんが。","ENG":"I don't know which mask you expected me to wear, but...","TWN":"雖然不知道你期待我戴上什麼面具。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어떤 가면이든 결국 저는 저예요. 전부 제가 내린 선택이랍니다.","JPN":"どんな仮面を被っても、私は私です。全部私が下した選択なのです。","ENG":"No matter the mask, I am still me. These are all the choices that I made.","TWN":"無論是何種面具，最終我還是我。這些都是我做出的選擇。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그저 당신에겐, 연기할 필요조차 못 느낄 뿐이고요.","JPN":"ただあなたには、演技する必要すら感じていないだけです。","ENG":"And to you, I just don't feel the necessity to act in front of you.","TWN":"只是對現在的你，我甚至不覺得有必要去演戲。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"I don't understand...","TWN":"你在說什麼……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"영양가 없는 대화였네요.","JPN":"意味のない会話でしたね。","ENG":"A fruitless conversation.","TWN":"無意義的對話啊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금은 그런 것보다 자기 몸 상태를 더 신경 써야 하지 않을까요?","JPN":"今はそんなことより、自分の体の方を気にするべきでは？","ENG":"Shouldn't you be more concerned about yourself right now?","TWN":"現在還是先顧下自己的身體狀況吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"어? 코피가……?","JPN":"え？　鼻血が……？","ENG":"Huh? A nosebleed...?","TWN":"咦？流鼻血了……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"……쿠헉!?","JPN":"……くはっ！？","ENG":"...Gah?!","TWN":"……咳嚇！？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"피를 토하는 걸 보니, 때마침 장기가 손상된 모양이네요.","JPN":"血を吐いたということは、内臓が損傷したようですね。","ENG":"Seeing how you're vomiting blood, your intestinal organs have finally been damaged.","TWN":"看你吐血的樣子，應該是內臟受損了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여긴 CSE 레벨 3에서 4를 오가는 준 고심도 지역이랍니다.","JPN":"ここはCSEレベル3から4を行き交う、準高深度地域ですよ。","ENG":"This is a semi-hyperdepth area with CSE Levels between 3 and 4.","TWN":"這裡是CSE等級在3到4之間徘徊的准高深度區域。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이터니움 실드가 남았다 하더라도, 상처를 입은 채 이곳 환경에 노출된 탓이겠죠.","JPN":"エタニウムシールドが残っているとはいえ、傷ついたままこの環境に長く晒されていたせいでしょう。","ENG":"Even if you have some remaining Eternium shield, it's probably because your wounds have been exposed to an environment like this.","TWN":"即使永恆之金護盾還在，也會因為受傷而暴露在這裡的環境中。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"자, 잠깐!","JPN":"ま、待て！","ENG":"W-wait!","TWN":"等，等等！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"커헉, 약속했잖아! 길을 안내해 주면 내 안전을 지켜주겠다고!","JPN":"かはっ……約束しただろう！　道を案内してあげれば、安全を保証してくれると！","ENG":"Gah...! You promised! That you'd guarantee my safety if I guided you down here!","TWN":"咳，你不是答應了嗎！只要我帶路，你就會保證我的安全！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네. 안전을 보장해 드린다고 했죠.","JPN":"はい。安全を保証すると言いましたね。","ENG":"Yes. I did say that.","TWN":"是的。我會保證你的安全。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"움직이지 못하게 되었을 때 부축해드리는 게 아니라.","JPN":"身動きがとれなくなった時、肩を貸すとは言っていません。","ENG":"But I didn't say that I'd help you out when you couldn't move.","TWN":"但若是你自己無法行動……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"무, 무슨 소리야! 애초에 이 상처도 네가……!","JPN":"な、何言ってるんだ！　そもそもこの傷は君が……！","ENG":"W-what?! I'm like this because of you...!","TWN":"你，你在說什麼呢！這傷口本來就是你……！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 당신이 죽인 동업자에게도 그렇게 말할 수 있나요?","JPN":"さあ、あなたが殺した同業者にも同じことが言えますか？","ENG":"Well, can you say the same thing to the colleagues you killed as well?","TWN":"呵，你能對你殺死的同伴也這麼說嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What did you say?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 동료를 쏴서, 부상당한 그를 미끼 삼아, 3종 침식체로부터 도망쳤을 텐데요?","JPN":"あなたも仲間を撃って、それをエサに第3種侵食体から逃げたんでしょう？","ENG":"You shot your colleagues, and used the injured as bait to flee from a Category 3, didn't you?","TWN":"你射擊了同伴，用受傷的他當誘餌，從3類侵蝕體那裡逃走吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그걸 네가 어떻게……?","JPN":"そ、それを君がどうして……？","ENG":"H-how do you know that...?","TWN":"那，那個你怎麼會知道……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그걸 제가 어떻게 알았는지는 중요하지 않겠죠.","JPN":"私がそれをなぜ知っているかは、重要なことではありません。","ENG":"It doesn't matter how I obtained this information.","TWN":"我怎麼知道的並不重要吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자, 일어나 두 다리로 걸으세요.","JPN":"さあ、立ち上がって自分の足で歩いてください。","ENG":"Now, get back up on your feet by yourself.","TWN":"來，站起來，邁開腿吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"방금처럼 침식체가 나타나면 당신의 안전을 지켜드리겠습니다.","JPN":"先ほどのように侵食体が現れたら、あなたの安全を守って差し上げます。","ENG":"If another C.O. appears, I will keep you safe.","TWN":"如果還有剛才那樣的侵蝕體出現，我會保護你的安全。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 발로 승강기까지 돌아갈 수 있다면.","JPN":"自分で昇降機まで戻ることができるなら、の話ですが。","ENG":"But only until you can get back on the lift yourself.","TWN":"只要你能自己走回電梯。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"커흑!! 이런 제기랄……!!","JPN":"くうっ！！　こんちくしょう……！！","ENG":"Gah!! Goddammit!","TWN":"咳！！該死的……！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"내가 못할 거 같아……? 내가 어떻게 여기까지 살아남았는데……!!","JPN":"やってやるさ……！！　今まで必死に生き残ってきたんだ……！！","ENG":"You think I can't do it...? Do you even know what I did to survive this far...?!","TWN":"你覺得我做不到嗎……？我可是費盡千辛萬苦才活到現在的……！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LIFTER_SWANSONG_NPC_NULL","text":{"KOREA":"할 수 있어……! 할 수 있다고……!!","JPN":"できる……！！　できるんだ……！！","ENG":"I'll show you...! I can do it...!!","TWN":"我能做到……！我一定能做到……！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIFTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요. 조금은 발을 맞춰 드리도록 하죠.","JPN":"いいでしょう。少しはペースを落としてあげます。","ENG":"Very well. I'll match your pace.","TWN":"很好。我會特意配合一下你的步調。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신 같은 엑스트라에게도 관객은 필요한 법이니까.","JPN":"あなたのようなエキストラにも観客は必要ですから。","ENG":"After all, even background characters like you need an audience.","TWN":"畢竟像你這樣的配角也是需要觀眾的。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"4-D 승강기 도착합니다!","JPN":"4-D昇降機、到着します！","ENG":"The 4-D elevator will arrive soon!","TWN":"4-D號升降機，已上升到地面！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"동행하셨던 리프터는 어떻게 됐어요?","JPN":"同行していたリフターはどうしたんですか？","ENG":"What happened to the lifter you were with?","TWN":"你同行的那個人怎麼了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"죽었어요…….","JPN":"……死亡、しました……","ENG":"He's dead...","TWN":"……他死了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"침식체가 나타나서 그만…….","JPN":"侵食体が現れて……あっという間に……","ENG":"A C.O. appeared out of the blue, and...","TWN":"侵蝕體出現了，結果……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"어이쿠.","JPN":"なんと……","ENG":"Oof.","TWN":"哎喲。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"그 양반 나름 베테랑이었는데 골로 가버렸네.","JPN":"あの人、結構ベテランだったのに逝っちまったか。","ENG":"That guy was a veteran. It's sad to see him go.","TWN":"那傢伙好歹也是個老手，結果還是掛了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"자자, 얼굴 펴고~ 이런 일 하다 보면 시체 좀 볼 수도 있지~","JPN":"ささ、そんな顔しないで。こんな仕事をしてると死体を見るのはつねだ。","ENG":"Now, now. Brighten up! You're bound to see a few bodies in this line of work!","TWN":"來來，笑一個~做這種工作，出人命也是常有的事～"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ENGINEER_NPC_NULL_NULL","text":{"KOREA":"리프터가 죽은 건, 죽은 거고. 정산은 하셔야죠.","JPN":"リフターのことは残念だけど、お会計はしないとね。","ENG":"The lifter who's dead is dead. But the bill still must be settled.","TWN":"升降人員死了就死了吧，但費用你還是得付。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"이제 남은 건, 두 곳.","JPN":"これで残りは二か所。","ENG":"Now, there are only two locations left.","TWN":"現在只剩下兩個地方了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"그렇다면 다음 촬영 일정이랑, 스케줄을 고려해서…… ","JPN":"次の撮影日程とスケジュールを考えて…… ","ENG":"Then, considering the schedule of the next shoot...","TWN":"那麼接下來的拍攝日程和行程安排……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"그래. 이제서야 모습을 드러내는군.","JPN":"やっと姿を現したな。","ENG":"Yes. So, now you show your face.","TWN":"好。現在終於現身了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"기다리고 있었다고, 모방범.","JPN":"待っていた、模倣犯。","ENG":"I've been waiting for you, copycat.","TWN":"我一直在等你，模仿犯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COUNTER_NPC_M_NULL","text":{"KOREA":"……크윽!!","JPN":"……くうっ！！","ENG":"...Kgh!!","TWN":"……咳呃！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COUNTER_NPC_M_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT"},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"……당신은?","JPN":"……あなたは？","ENG":"...You are?","TWN":"……你是？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"광대놀음은 거기까지야.","JPN":"お遊びはそこまでだ。","ENG":"Your fooling around ends here.","TWN":"小丑表演到此為止。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"순순히 포기하시지.","JPN":"大人しく諦めろ。","ENG":"Give up.","TWN":"乖乖放棄吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이지수……!","JPN":"ムラサメ・シノ……！","ENG":"Lee Jisoo...!","TWN":"李智秀……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"보아하니, 감시역으로 붙어 있던 금발 원숭이를 떼 놓은 모양이군.","JPN":"見たところ、監視役の金髪サルは振り切ったようだな。","ENG":"From the looks of it, the blonde monkey I put to keep an eye on you is no longer with you.","TWN":"看來，你已經擺脫了那個金髮猴子的監視了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그 말은, 대장 말대로 이 세계에 보통 사람은 인지할 수 없는 변화가 일어났다는 거겠지.","JPN":"ということは、隊長の言うとおり普通の人間では認知できないような変化が起きているということだろう。","ENG":"That means, like Commander said, a change in the world that ordinary people can't perceive has occurred.","TWN":"那就是說，正如隊長所言，這個世界發生了普通人無法察覺的變化吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그리고 그 변화가 별 볼일 없는 것이었다면.","JPN":"しかもその変化が気にとめるほどのことじゃないなら……","ENG":"And if that change is something insignificant.","TWN":"如果那些變化無關緊要的話。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"네가 이렇게 전 세계 대균열을 들쑤시며 수상한 짓을 벌이고 다닐 리도 없을 테고.","JPN":"お前がこうやって全世界の大亀裂に入り込んで、怪しい行動をする必要もなかっただろうな。","ENG":"You wouldn't be going through all the world's Grand Dimension Crevices doing suspicious activities.","TWN":"你也不會在世界各地的大峽谷中搞這些可疑的事情。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"의외로군요.","JPN":"意外ですね。","ENG":"How surprising.","TWN":"真是意外啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대장님의 성격상, 배우로 일하고 있는 동안에는 노려질 일이 없다고 생각했는데.","JPN":"隊長の性格からして、役者として働いている間は狙われることはないと思っていたのですが。","ENG":"Given Commander's personality, he said that I wouldn't be targeted while I worked as an actress.","TWN":"以隊長的性格來看，是不會在我用演員身份的時候動手的吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이렇게 무대의 뒤편에 있을 때 습격을 받을 줄은 몰랐네요.","JPN":"今のように舞台裏にいる時に襲われることになるとは。","ENG":"Didn't imagine that I'd be ambushed like this behind the stage.","TWN":"沒想到在幕後也會遭到襲擊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 눈……. 그 <color=#ffd34c>운명을 꿰뚫는 눈</color>으로 제 모습을 간파해 낸 건가요?","JPN":"その目……その<color=#ffd34c>運命を見抜く目</color>で、私の素顔を見抜いたのですか？","ENG":"That eye... The <color=#ffd34c>eye that sees through fate</color>. Did you figure out who I was with that?","TWN":"那只眼睛……你是用那<color=#ffd34c>洞悉命運的眼睛</color>看穿的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"어떤 흉내를 내든 간, 네 과거는 불로 지진 낙인처럼 지워질 일 없을 테니까.","JPN":"誰を真似ようが、お前の過去は焼印のように消えないだろうからな。","ENG":"Whoever you try to pretend to be, your past will never be erased like a brand by fire.","TWN":"無論你怎麼模仿，你的過去就像被火焰灼燒的烙印，永遠無法抹去。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그때도 그랬고……. 지금도 그렇지.","JPN":"あの頃も……そして今も。","ENG":"Not then... and not even now.","TWN":"當時是這樣……現在也是。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마치, 전부 다 꿰뚫어 보고 있다는 듯이 말씀하시는군요.","JPN":"まるで全部お見通しだというかのような口ぶりですね。","ENG":"It's as if you're seeing through everything.","TWN":"你說話的樣子，仿佛已經看穿了一切呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"물론이야. 네 과거를 보게 되면, 네가 무슨 짓을 하려는 지도 대충 예상되거든.","JPN":"もちろんだ。お前の過去を覗くと、お前が何をしようとしているのかもだいたい予想がつく。","ENG":"Of course. When I see your past, I can guess as to what you've been up to.","TWN":"當然了。看看你的過去，就大概能猜到你想幹什麼了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"스완 클레어. 아니…….","JPN":"スワン・クレア。いや……","ENG":"Swan Claire. No–","TWN":"史旺·克萊爾。不……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이상하군요!","JPN":"おかしいですね。","ENG":"That's odd!","TWN":"不對！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거기까지 알고 계셨으면서 왜 퍼스트윙에게는 아무런 언질을 주지 않은 거죠?","JPN":"そこまで知っておきながら、なぜファーストウイングには何も教えなかったのですか？","ENG":"If you knew that much, then why didn't you give Firstwing a notice in advance?","TWN":"既然你知道那麼多，為什麼不告訴弗斯特薇一點消息呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신을 통해, 퍼스트윙이 제 과거에 대해 들었다면, 순순히 당하지는 않았을 텐데요?","JPN":"あなたが私の過去についてファーストウイングに教えていれば、大人しくやられたりなんかしなかったはずです。","ENG":"If Firstwing heard about my past through you, she wouldn't have gone down so easily.","TWN":"如果透過你，弗斯特薇知道了我的過去，就不會那麼輕易地失敗了吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"이 눈은 네가 생각하는 것과 다르거든.","JPN":"この目は、お前が思っているのとは違うんだよ。","ENG":"This eye is different from what you think it is.","TWN":"這只眼睛和你想的不一樣。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"보고 싶다고, 볼 수 있는 게 아니고. 보고 싶지 않다고, 보지 않을 수 있는 게 아니야.","JPN":"見たいからって見られるわけでも、見たくないからって見ずに済むわけでもない。","ENG":"It doesn't allow me to see or not see at will.","TWN":"不是想看就能看到的，也不是不想看就能不看的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"늘 그렇듯.","JPN":"いつもそうさ。","ENG":"As always.","TWN":"還是老樣子。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지수씨는 참 변명이 서투시네요.","JPN":"あなたは言い訳が下手ですね。","ENG":"You're awkward with excuses, Jisoo.","TWN":"智秀，你真是不擅長找藉口啊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"너무 솔직한 여자는 매력이 없는 법이랍니다.","JPN":"正直すぎる女は魅力がありませんよ。","ENG":"A woman who's too honest is not attractive.","TWN":"太過坦率的女人是沒有魅力的喔。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"……헛소리.","JPN":"……戯言を。","ENG":"...That's nonsense.","TWN":"……你在說什麼。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저에게 당신과 같은 눈은 없지만, 그 이유가 뭔지 대강은 짐작이 가네요.","JPN":"私にはあなたのような目はないけど、その理由はだいたい予想がつきます。","ENG":"I may not have an eye like yours, but I have a suspicion about your reasons.","TWN":"雖然我沒有和你一樣的眼睛，但我大概能知道到原因。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"한 번 맞춰볼까요?","JPN":"当ててみましょうか？","ENG":"May I take a guess?","TWN":"就讓我來猜猜看吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국, 육익이라는 조직의 결속력이 그 정도라는 뜻이겠죠.","JPN":"つまり、六翼という組織の結束力はその程度ということです。","ENG":"In the end, it means that Six Wings' solidarity is only to that extent.","TWN":"所以，這表示六翼的凝聚力也不過如此。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대장님 혼자 모든 정보를 통제하고 있으니까요.","JPN":"隊長が一人ですべての情報を統制している。","ENG":"For Commander does control all the information himself.","TWN":"隊長一個人掌握著所有資訊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그렇다 하더라도 달라질 건 없어.","JPN":"だからと言って何も変わることはない。","ENG":"But even if so, nothing will change.","TWN":"即便如此，也不會有任何改變。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"너는 여기서 스러지고…….","JPN":"お前はここで倒れ……","ENG":"You will go down here...","TWN":"你會在這裡倒下……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"나는 마지막까지 그분을 따르겠다.","JPN":"私は最後まであの方についていく。","ENG":"and I will follow him until the end.","TWN":"而我，會追隨他到最後。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신 말이 맞네요.","JPN":"あなたの言う通りです。","ENG":"You're right.","TWN":"你說的沒錯。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"남의 운명은 훤히 꿰뚫어 보면서, 훤히 보이는 자기 운명은 꿰뚫지 못해요. 당신은.","JPN":"他人の運命ははっきりと見抜けるのに、すぐ目の前の自分の運命は見抜けない。","ENG":"You might see clearly into others' fate, but can't see through your own, which is nearly transparent.","TWN":"你能看透別人的命運，卻看不清自己的命運。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 한때 동료로서 당신의 앞날 스포일러를 남겨드리죠.","JPN":"かつての仲間として、あなたの未来をネタバレさせましょう。","ENG":"Then, allow me to give you a slight spoiler for your future out of respect of being a former colleague.","TWN":"那麼，作為曾經的同伴，我就給你劇透一下你的未來吧。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 그 충의는 결코 보답받지 못할 거예요.","JPN":"あなたのその忠義は、決して報われないでしょう。","ENG":"Your loyalty will never be repaid.","TWN":"你的忠誠永遠不會得到回報。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};